#include "controller.h"

static bool controller_is_timed_out(const controller_t *controller, uint32_t now_ms)
{
    if (controller == NULL) {
        return false;
    }

    if (controller->has_valid_pressure &&
        (uint32_t) (now_ms - controller->last_pressure_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return true;
    }

    if (controller->has_valid_door &&
        (uint32_t) (now_ms - controller->last_door_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return true;
    }

    return false;
}

static controller_output_t controller_make_safe_output(const controller_t *controller, bool timed_out)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_ID_SAFE_VENT,
        .state_name = CONTROLLER_STATE_SAFE_VENT,
        .changed = false,
        .timed_out = timed_out,
    };

    if (controller != NULL) {
        output.changed = controller->compressor_on != output.compressor_on ||
                         controller->vent_open != output.vent_open;
    }

    return output;
}

// Initialize the controller
void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_ID_SAFE_VENT;
    controller->has_valid_pressure = false;
    controller->last_pressure_kpa = 0;
    controller->last_pressure_ms = 0U;
    controller->has_valid_door = false;
    controller->door_closed = false;
    controller->last_door_ms = 0U;
}

// Step the controller based on input
controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    if (controller == NULL) {
        return (controller_output_t) {
            .compressor_on = false,
            .vent_open = true,
            .state = CONTROLLER_STATE_ID_SAFE_VENT,
            .state_name = CONTROLLER_STATE_SAFE_VENT,
            .changed = false,
            .timed_out = false,
        };
    }

    const bool previous_compressor_on = controller->compressor_on;
    const bool previous_vent_open = controller->vent_open;
    const controller_state_t previous_state = controller->state;

    bool timed_out = false;
    bool force_safe_vent = false;

    switch (input.kind) {
    case CONTROLLER_INPUT_PRESSURE:
        controller->has_valid_pressure = true;
        controller->last_pressure_kpa = input.pressure_kpa;
        controller->last_pressure_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_DOOR_OPEN:
        controller->has_valid_door = true;
        controller->door_closed = false;
        controller->last_door_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_DOOR_CLOSED:
        controller->has_valid_door = true;
        controller->door_closed = true;
        controller->last_door_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        force_safe_vent = true;
        timed_out = true;
        break;
    case CONTROLLER_INPUT_INVALID_PRESSURE:
    case CONTROLLER_INPUT_INVALID_DOOR:
        force_safe_vent = true;
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        break;
    }

    const bool sensors_ready = controller->has_valid_pressure && controller->has_valid_door;
    if (sensors_ready && controller_is_timed_out(controller, input.now_ms)) {
        force_safe_vent = true;
        timed_out = true;
    }

    bool next_compressor_on = previous_compressor_on;
    bool next_vent_open = previous_vent_open;
    controller_state_t next_state = previous_state;

    if (force_safe_vent || !sensors_ready) {
        next_compressor_on = false;
        next_vent_open = true;
        next_state = CONTROLLER_STATE_ID_SAFE_VENT;
    } else if (!controller->door_closed) {
        next_compressor_on = false;
        next_vent_open = true;
        next_state = CONTROLLER_STATE_ID_SAFE_VENT;
    } else if (controller->last_pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
        next_compressor_on = true;
        next_vent_open = false;
        next_state = CONTROLLER_STATE_ID_PRESSURIZING;
    } else if (controller->last_pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
        next_compressor_on = false;
        next_vent_open = true;
        next_state = CONTROLLER_STATE_ID_RELIEVING;
    } else {
        next_compressor_on = previous_compressor_on;
        next_vent_open = previous_vent_open;
        next_state = CONTROLLER_STATE_ID_HOLDING;
    }

    controller->compressor_on = next_compressor_on;
    controller->vent_open = next_vent_open;
    controller->state = next_state;

    controller_output_t output = {
        .compressor_on = next_compressor_on,
        .vent_open = next_vent_open,
        .state = next_state,
        .state_name = controller_state_name(next_state),
        .changed = (next_compressor_on != previous_compressor_on) || (next_vent_open != previous_vent_open),
        .timed_out = timed_out,
    };

    return output;
}

// Get state name for a given state
const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_ID_SAFE_VENT:
        return CONTROLLER_STATE_SAFE_VENT;
    case CONTROLLER_STATE_ID_PRESSURIZING:
        return CONTROLLER_STATE_PRESSURIZING;
    case CONTROLLER_STATE_ID_HOLDING:
        return CONTROLLER_STATE_HOLDING;
    case CONTROLLER_STATE_ID_RELIEVING:
        return CONTROLLER_STATE_RELIEVING;
    default:
        return CONTROLLER_STATE_SAFE_VENT;
    }
}

